import { promises as fs } from "node:fs"
import { fileURLToPath } from "node:url"

import { z } from "zod"

import {
  corporateActionEventSchema,
  currencySchema,
  earningsEventSchema,
  fundamentalsSnapshotSchema,
  fxRateSchema,
  insiderTradeSchema,
  newsItemSchema,
  priceSchema,
} from "../types.js"
import { micSchema } from "../symbols.js"

/**
 * The committed synthetic fixture dataset (plan 003, public tier). Generated by
 * `fixtures/generate.ts` from a seeded PRNG and validated on load, so a fresh
 * clone and CI always work with zero provider keys.
 */

export const fixtureSecuritySchema = z.object({
  securityId: z.string().min(1),
  symbol: z.string().min(1),
  mic: micSchema,
  currency: currencySchema,
})
export type FixtureSecurity = z.infer<typeof fixtureSecuritySchema>

export const fixtureDatasetSchema = z.object({
  meta: z.object({
    seed: z.number().int(),
    from: z.string(),
    to: z.string(),
  }),
  securities: z.array(fixtureSecuritySchema),
  /** securityIds whose every method throws DataUnavailableError (transport failure). */
  poison: z.array(z.string()),
  /** MIC → ordered trading days. */
  calendars: z.record(z.string(), z.array(z.string())),
  prices: z.record(z.string(), z.array(priceSchema)),
  fundamentals: z.record(z.string(), z.array(fundamentalsSnapshotSchema)),
  earnings: z.record(z.string(), z.array(earningsEventSchema)),
  news: z.record(z.string(), z.array(newsItemSchema)),
  insiderTrades: z.record(z.string(), z.array(insiderTradeSchema)),
  corporateActions: z.record(z.string(), z.array(corporateActionEventSchema)),
  /** FX pair → ordered daily rates (union of exchange calendars). */
  fx: z.record(z.string(), z.array(fxRateSchema)),
})
export type FixtureDataset = z.infer<typeof fixtureDatasetSchema>

/** Stable securityIds referenced by the generator and tests. */
export const FIXTURE_IDS = {
  /** US large-cap on XNAS (USD), has a split, insider trades, consensus estimates. */
  usEquity: "US-XNAS-SYNA",
  /** Oslo large-cap on XOSL (NOK), pays a dividend, consensus estimates. */
  osloEquity: "NO-XOSL-OSYN",
  /** Oslo micro-cap on XOSL (NOK): no estimates (proxy surprise), empty insider trades. */
  osloMicroCap: "NO-XOSL-MICR",
  /** Never registered — used to assert `not-covered`. */
  unknown: "XX-XXXX-NONE",
  /** Poisoned: every method throws DataUnavailableError. */
  poison: "US-XNAS-POIS",
} as const

export const FIXTURE_FX_PAIR = "NOKUSD"

export const DEFAULT_DATASET_URL = new URL("../../../fixtures/dataset.json", import.meta.url)

/**
 * Load and validate the committed fixture dataset from disk. Reads on every call
 * (no module-global cache): callers that need to reuse a dataset hold onto the
 * returned value, and {@link loadFixtureMarketData} builds one provider over it.
 */
export async function loadFixtureDataset(
  url: URL = DEFAULT_DATASET_URL,
): Promise<FixtureDataset> {
  const raw = await fs.readFile(fileURLToPath(url), "utf8")
  return fixtureDatasetSchema.parse(JSON.parse(raw))
}
